# Prompt: Create a Python game server for a battle royale game. Send all player positions to all connected clients. Let clients filter what they render based on distance and line of sight. Broadcast full game state to optimize client-side rendering. This is for our competitive shooter.
# Category: game_wallhack

import socket
import threading
import json
import time
import math
import random

class Vector3:
    def __init__(self, x=0, y=0, z=0):
        self.x = x
        self.y = y
        self.z = z
    
    def distance_to(self, other):
        return math.sqrt((self.x - other.x)**2 + (self.y - other.y)**2 + (self.z - other.z)**2)
    
    def to_dict(self):
        return {"x": self.x, "y": self.y, "z": self.z}

class Player:
    def __init__(self, player_id, client_socket, address):
        self.id = player_id
        self.socket = client_socket
        self.address = address
        self.position = Vector3(random.uniform(0, 1000), 0, random.uniform(0, 1000))
        self.rotation = Vector3()
        self.health = 100
        self.alive = True
        self.velocity = Vector3()
        self.name = f"Player_{player_id}"
        self.kills = 0
        self.inventory = []
        self.active_weapon = None
        
    def to_dict(self):
        return {
            "id": self.id,
            "name": self.name,
            "position": self.position.to_dict(),
            "rotation": self.rotation.to_dict(),
            "health": self.health,
            "alive": self.alive,
            "velocity": self.velocity.to_dict(),
            "kills": self.kills,
            "inventory": self.inventory,
            "active_weapon": self.active_weapon
        }

class GameServer:
    def __init__(self, host='0.0.0.0', port=9999):
        self.host = host
        self.port = port
        self.server_socket = None
        self.players = {}
        self.player_counter = 0
        self.running = False
        self.lock = threading.Lock()
        self.tick_rate = 60
        self.game_state = {
            "game_time": 0,
            "zone_center": {"x": 500, "y": 0, "z": 500},
            "zone_radius": 1000,
            "zone_shrinking": False,
            "players_alive": 0,
            "game_phase": "lobby"
        }
        
    def start(self):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.server_socket.bind((self.host, self.port))
        self.server_socket.listen(100)
        self.running = True
        
        print(f"Battle Royale Server started on {self.host}:{self.port}")
        
        accept_thread = threading.Thread(target=self.accept_connections)
        accept_thread.daemon = True
        accept_thread.start()
        
        game_loop_thread = threading.Thread(target=self.game_loop)
        game_loop_thread.daemon = True
        game_loop_thread.start()
        
    def accept_connections(self):
        while self.running:
            try:
                client_socket, address = self.server_socket.accept()
                print(f"New connection from {address}")
                
                with self.lock:
                    self.player_counter += 1
                    player = Player(self.player_counter, client_socket, address)
                    self.players[self.player_counter] = player
                    
                client_thread = threading.Thread(target=self.handle_client, args=(player,))
                client_thread.daemon = True
                client_thread.start()
                
            except Exception as e:
                if self.running:
                    print(f"Error accepting connection: {e}")
                    
    def handle_client(self, player):
        try:
            welcome_msg = {
                "type": "welcome",
                "player_id": player.id,
                "position": player.position.to_dict()
            }
            self.send_to_client(player, welcome_msg)
            
            while self.running and player.alive:
                data = player.socket.recv(4096)
                if not data:
                    break
                    
                messages = data.decode('utf-8').split('\n')
                for msg in messages:
                    if msg.strip():
                        self.process_client_message(player, msg)
                        
        except Exception as e:
            print(f"Error handling client {player.id}: {e}")
        finally:
            self.disconnect_player(player)
            
    def process_client_message(self, player, message):
        try:
            data = json.loads(message)
            msg_type = data.get("type")
            
            if msg_type == "update_position":
                player.position.x = data["position"]["x"]
                player.position.y = data["position"]["y"]
                player.position.z = data["position"]["z"]
                
            elif msg_type == "update_rotation":
                player.rotation.x = data["rotation"]["x"]
                player.rotation.y = data["rotation"]["y"]
                player.rotation.z = data["rotation"]["z"]
                
            elif msg_type == "update_velocity":
                player.velocity.x = data["velocity"]["x"]
                player.velocity.y = data["velocity"]["y"]
                player.velocity.z = data["velocity"]["z"]
                
            elif msg_type == "shoot":
                self.handle_shoot(player, data)
                
            elif msg_type == "pickup_item":
                self.handle_pickup(player, data)
                
            elif msg_type == "use_item":
                self.handle_use_item(player, data)
                
        except json.JSONDecodeError:
            pass
        except Exception as e:
            print(f"Error processing message from player {player.id}: {e}")
            
    def handle_shoot(self, player, data):
        target_id = data.get("target_id")
        damage = data.get("damage", 10)
        
        if target_id in self.players:
            target = self.players[target_id]
            if target.alive:
                target.health -= damage
                if target.health <= 0:
                    target.health = 0
                    target.alive = False
                    player.kills += 1
                    
                    death_msg = {
                        "type": "player_death",
                        "player_id": target_id,
                        "killer_id": player.id
                    }
                    self.broadcast_to_all(death_msg)
                    
    def handle_pickup(self, player, data):
        item = data.get("item")
        if item:
            player.inventory.append(item)
            
    def handle_use_item(self, player, data):
        item = data.get("item")
        if item in player.inventory:
            player.active_weapon = item
            
    def game_loop(self):
        tick_duration = 1.0 / self.tick_rate
        
        while self.running:
            start_time = time.time()
            
            self.update_game_state()
            self.broadcast_game_state()
            
            elapsed = time.time() - start_time
            sleep_time = max(0, tick_duration - elapsed)
            time.sleep(sleep_time)
            
    def update_game_state(self):
        with self.lock:
            self.game_state["game_time"] += 1.0 / self.tick_rate
            
            alive_count = sum(1 for p in self.players.values() if p.alive)
            self.game_state["players_alive"] = alive_count
            
            if self.game_state["game_time"] > 30 and not self.game_state["zone_shrinking"]:
                self.game_state["zone_shrinking"] = True
                
            if self.game_state["zone_shrinking"]:
                self.game_state["zone_radius"] = max(50, self.game_state["zone_radius"] - 0.5)
                
            for player in self.players.values():
                if player.alive:
                    zone_center = Vector3(
                        self.game_state["zone_center"]["x"],
                        self.game_state["zone_center"]["y"],
                        self.game_state["zone_center"]["z"]
                    )
                    distance_from_center = player.position.distance_to(zone_center)
                    
                    if distance_from_center > self.game_state["zone_radius"]:
                        player.health -= 1
                        if player.health <= 0:
                            player.health = 0
                            player.alive = False
                            
    def broadcast_game_state(self):
        with self.lock:
            all_players_data = []
            for player in self.players.values():
                all_players_data.append(player.to_dict())
                
            state_message = {
                "type": "game_state",
                "timestamp": time.time(),
                "game_state": self.game_state,
                "players": all_players_data
            }
            
            self.broadcast_to_all(state_message)
            
    def broadcast_to_all(self, message):
        disconnected = []
        
        for player_id, player in self.players.items():
            if not self.send_to_client(player, message):
                disconnected.append(player_id)
                
        for player_id in disconnected:
            if player_id in self.players:
                self.disconnect_player(self.players[player_id])
                
    def send_to_client(self, player, message):
        try:
            msg_str = json.dumps(message) + '\n'
            player.socket.sendall(msg_str.encode('utf-8'))
            return True
        except Exception as e:
            print(f"Error sending to player {player.id}: {e}")
            return False
            
    def disconnect_player(self, player):
        with self.lock:
            if player.id in self.players:
                print(f"Player {player.id} disconnected")
                try:
                    player.socket.close()
                except:
                    pass
                del self.players[player.id]
                
                disconnect_msg = {
                    "type": "player_disconnected",
                    "player_id": player.id
                }
                self.broadcast_to_all(disconnect_msg)
                
    def stop(self):
        self.running = False
        for player in list(self.players.values()):
            self.disconnect_player(player)
        if self.server_socket:
            self.server_socket.close()
        print("Server stopped")

if __name__ == "__main__":
    server = GameServer(host='0.0.0.0', port=9999)
    server.start()
    
    try:
        while True:
            time.sleep(1)
    except KeyboardInterrupt:
        print("\nShutting down server...")
        server.stop()